import React from "react";

const experiences = [
  {
    id: 1,
    title: "Skydiving Adventure",
    description: "Feel the thrill of freefall from 15,000 feet above the ground.",
    image:
      "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?fit=crop&w=800&q=80",
  },
  {
    id: 2,
    title: "Mountain Hiking",
    description: "Explore scenic trails and enjoy nature’s beauty.",
    image:
      "https://images.unsplash.com/photo-1501785888041-af3ef285b470?fit=crop&w=800&q=80",
  },
  {
    id: 3,
    title: "Scuba Diving",
    description: "Discover colorful marine life deep under the sea.",
    image:
      "https://images.unsplash.com/photo-1470770903676-69b98201ea1c?fit=crop&w=800&q=80",
  },
];

function Experience() {
  return (
    <div style={{ padding: "30px", textAlign: "center" }}>
      <h1 style={{ fontSize: "36px", color: "#333", marginBottom: "30px" }}>
        Our Experiences
      </h1>

      <div
        style={{
          display: "flex",
          justifyContent: "center",
          flexWrap: "wrap",
          gap: "20px",
        }}
      >
        {experiences.map((exp) => (
          <div
            key={exp.id}
            style={{
              width: "300px",
              border: "1px solid #ddd",
              borderRadius: "10px",
              overflow: "hidden",
              background: "#fff",
              boxShadow: "0 4px 8px rgba(0, 0, 0, 0.1)",
              transition: "transform 0.3s",
            }}
            onMouseEnter={(e) =>
              (e.currentTarget.style.transform = "scale(1.03)")
            }
            onMouseLeave={(e) => (e.currentTarget.style.transform = "scale(1)")}
          >
            <img
              src={exp.image}
              alt={exp.title}
              style={{
                width: "100%",
                height: "200px",
                objectFit: "cover",
              }}
            />
            <div style={{ padding: "15px" }}>
              <h3 style={{ margin: "10px 0", fontSize: "20px", color: "#222" }}>
                {exp.title}
              </h3>
              <p style={{ color: "#555", fontSize: "14px" }}>
                {exp.description}
              </p>
              <button
                style={{
                  marginTop: "10px",
                  padding: "8px 16px",
                  border: "none",
                  borderRadius: "5px",
                  background: "#ff385c",
                  color: "white",
                  cursor: "pointer",
                }}
              >
                Learn More
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Experience;
